import functools
import time

def retry(func):
    """
    A decorator that retries a function up to 3 times if an exception is raised.
    """
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        max_attempts = 3
        last_exception = None

        for attempt in range(1, max_attempts + 1):
            try:
                return func(*args, **kwargs)
            except Exception as e:
                last_exception = e
                print(f"Attempt {attempt} failed for '{func.__name__}': {e}")

                if attempt < max_attempts:
                    print(f"Retrying... ({attempt}/{max_attempts})")
                    time.sleep(0.5)
                else:
                    print(f"All {max_attempts} attempts failed.")

        raise last_exception

    return wrapper

# --- Example Usage ---
if __name__ == "__main__":
    # Counter to simulate a function that fails a specific number of times
    failure_tracker = {"count": 0}

    @retry
    def unstable_function(fail_until_attempt):
        """A function that raises an error until a specific attempt count is reached."""
        failure_tracker["count"] += 1
        if failure_tracker["count"] < fail_until_attempt:
            raise ValueError(f"Simulated error on attempt {failure_tracker['count']}")
        return "Success!"

    print("--- Scenario 1: Function succeeds on 3rd attempt ---")
    try:
        result = unstable_function(fail_until_attempt=3)
        print(f"Final Result: {result}")
    except Exception as e:
        print(f"Caught final exception: {e}")

    print("\n--- Scenario 2: Function fails all 3 attempts ---")
    # Reset tracker
    failure_tracker["count"] = 0
    try:
        # Set threshold higher than the retry limit to force failure
        result = unstable_function(fail_until_attempt=5)
        print(f"Final Result: {result}")
    except Exception as e:
        print(f"Caught final exception: {e}")
